class Solution {
public:
    int binaryGap(int n) {
        int maxGap = 0;
        int lastOne = -1;
        while (n > 0) {
            if (n & 1) {
                if (lastOne != -1) {
                    maxGap = max(maxGap, n - lastOne - 1);
                }
                lastOne = n;
            }
            n >>= 1;
        }
        return maxGap;
    }
};
